let newsList = "";
let count = 0;

// Filtramos y agrupamos
for (const item of items) {
  if (count < 8) {
    newsList += `--- NOTICIA ${count + 1} ---\n`;
    newsList += `TITULO: ${item.json.title}\n`;
    newsList += `LINK: ${item.json.link}\n`;
    newsList += `FECHA: ${item.json.pubDate}\n`;
    newsList += `RESUMEN: ${item.json.contentSnippet || item.json.content}\n\n`;
    count++;
  }
}

return [{
  json: {
    news_summary: newsList
  }
}];

const rawText = $input.first().json?.content?.parts?.[0]?.text || "";
if (!rawText) throw new Error("Gemini devolvio texto vacio.");

let jsonString = rawText.trim();

const fenceMatch = jsonString.match(/```(?:json)?\s*([\s\S]*?)```/);
if (fenceMatch) jsonString = fenceMatch[1].trim();

let parsed;
try {
    parsed = JSON.parse(jsonString);
} catch (e) {
    const objectMatch = jsonString.match(/\{[\s\S]*\}/);
    if (!objectMatch) throw new Error("No JSON found in response");
    let candidate = objectMatch[0];
    try {
          parsed = JSON.parse(candidate);
    } catch (e2) {
          let fixed = candidate.replace(/(?<=:\s*\")([\s\S]*?)(?=\"\s*[,\}])/g, (match) => {
                  return match.replace(/\n/g, "\\n").replace(/(?<!\\)\"/g, "\\\"");
          });
          try {
                  parsed = JSON.parse(fixed);
          } catch (e3) {
                  throw new Error("Could not fix JSON: " + e3.message);
          }
    }
}

function limpiarSlug(texto) {
    if (!texto) return "noticia-" + Date.now();
    return texto.toString().toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").trim().replace(/\s+/g, "-").replace(/[^\w\-]+/g, "").replace(/\-\-+/g, "-").substring(0, 40);
}

const titulo = parsed.titulo || parsed.title_en || parsed.title || "";
const slug = limpiarSlug(parsed.slug || titulo);
const contenido_html = parsed.contenido_html || parsed.content_markdown_en || "";
const resumen_aprobacion = parsed.resumen_aprobacion || parsed.approval_summary_es || parsed.summary_es || "";
const categoria = parsed.categoria || "politica";

return [{
    json: {
        titulo,
        slug,
        contenido_html,
        resumen_aprobacion,
        categoria
    }
}];

