const input = $input.first().json;
const cb = input.callback_query || input;
const data = (cb.data || '').trim();
const cbId = cb.id || input.callback_query_id || '';
let action = 'unknown';
let slug = '';
if (data.startsWith('publish:')) {
  action = 'publish';
  slug = data.slice('publish:'.length);
} else if (data === 'discard') {
  action = 'discard';
}
return [{ json: { action, slug, cbId, callback_data: data } }];

const publishedSlugs = $('Leer Slugs Publicados').all().map(item => item.json.slug);
const inputItems = $input.all();
const newItems = [];
for (let item of inputItems) {
    // Generate a quick slug from title to check duplicates if possible
    // Here we just pass it through or implement basic check
    newItems.push(item);
}
return newItems;
